def encode_nrz_l(bits):
    """Non-Return-to-Zero Level encoding"""
    signal = []
    for bit in bits:
        signal.append(1 if bit == '1' else -1)
    return signal

def encode_nrz_i(bits):
    """Non-Return-to-Zero Inverted encoding"""
    signal = []
    current_level = 1
    for bit in bits:
        if bit == '1':
            current_level = -current_level
        signal.append(current_level)
    return signal

def encode_manchester(bits):
    """Manchester encoding (IEEE 802.3)"""
    signal = []
    for bit in bits:
        if bit == '1':
            signal.extend([1, -1])  # High to Low
        else:
            signal.extend([-1, 1])  # Low to High
    return signal

def encode_differential_manchester(bits):
    """Differential Manchester encoding (IEEE 802.5)"""
    signal = []
    current_level = 1
    for bit in bits:
        if bit == '0':
            current_level = -current_level
        signal.extend([current_level, -current_level])
    return signal

# Test with sample data
data_bits = '10111001'
print(f"Original bits: {data_bits}")
print(f"NRZ-L:    {encode_nrz_l(data_bits)}")
print(f"NRZ-I:    {encode_nrz_i(data_bits)}")
print(f"Manch:    {encode_manchester(data_bits)}")
print(f"Diff-Man: {encode_differential_manchester(data_bits)}")
